input.content:
{
  "openapi": "3.1.0",
  "info": {
    "title": "Renewable Energy Executive Dashboard API",
    "description": "FastAPI backend serving renewable energy research data for the executive dashboard. All data is derived from the March 2026 research phase covering the North American construction industry.\n\n**Research confidence levels:**\n- `HIGH` – multiple corroborating sources\n- `MEDIUM` – single reliable source or partial data\n- `LOW` – inference from related data or limited sourcing",
    "version": "1.0.0",
    "contact": {
      "name": "Technology Services Group",
      "email": "tsg@example.com"
    }
  },
  "servers": [
    {
      "url": "http://localhost:8000",
      "description": "Local development server"
    }
  ],
  "paths": {
    "/health": {
      "get": {
        "tags": ["System"],
        "summary": "Health check",
        "description": "Returns the current health status of the API and its database connection.",
        "operationId": "health_check",
        "responses": {
          "200": {
            "description": "Service is healthy",
            "content": {
              "application/json": {
                "schema": { "$ref": "#/components/schemas/HealthResponse" },
                "example": {
                  "status": "ok",
                  "version": "1.0.0",
                  "timestamp": "2026-03-28T14:00:00Z",
                  "database": "ok",
                  "uptime_seconds": 3600.5
                }
              }
            }
          },
          "503": {
            "description": "Service degraded or unavailable",
            "content": {
              "application/json": {
                "schema": { "$ref": "#/components/schemas/ErrorDetail" }
              }
            }
          }
        }
      }
    },

    "/api/market-trends": {
      "get": {
        "tags": ["Market Data"],
        "summary": "Adoption rates and market size data",
        "description": "Returns global and North American green building market size data, electric construction equipment market data, IRA incentive totals, adoption rates by firm size, time-series projections, and key market drivers and barriers.\n\n**Key data points:**\n- Global green building market: $618.58B (2025) → $1,374.23B (2034), CAGR 9.29%\n- North America: ~35% of global market ($153.87B in 2025)\n- Electric construction equipment: $13.63–15.77B (2025), projected $34.72B by 2030 (CAGR 20.5%)\n- Mid-size firms ($50M–$500M): 40–55% have adopted some renewable energy strategy",
        "operationId": "get_market_trends",
        "responses": {
          "200": {
            "description": "Market trends data",
            "content": {
              "application/json": {
                "schema": { "$ref": "#/components/schemas/MarketTrendsResponse" }
              }
            }
          }
        }
      }
    },

    "/api/regional-data": {
      "get": {
        "tags": ["Market Data"],
        "summary": "North American regional breakdown",
        "description": "Returns USGBC Top 10 States for LEED (2024 and 2025), country-level data for USA, Canada, and Mexico, and key state/provincial policy drivers.\n\n**Key data points:**\n- US: 56M gross sq meters LEED-certified space (global leader)\n- Canada: 10.07M sq meters, 2nd globally; Canada Green Buildings Strategy 2024\n- Mexico: 2.27M sq meters, 6th globally; first LEED v5 O+M and industrial certifications",
        "operationId": "get_regional_data",
        "responses": {
          "200": {
            "description": "Regional breakdown data",
            "content": {
              "application/json": {
                "schema": { "$ref": "#/components/schemas/RegionalDataResponse" }
              }
            }
          }
        }
      }
    },

    "/api/technologies": {
      "get": {
        "tags": ["Technology"],
        "summary": "Technology catalog with feasibility scores and ROI",
        "description": "Returns all tracked renewable energy and green building technologies with feasibility scores (0–10), ROI metrics, payback estimates, and adoption data.\n\n**Technologies covered:**\n- Electric Construction Equipment (excavators, cranes, loaders)\n- Solar PV (on-site, BIPV)\n- Green Building Systems (HVAC, LED, stormwater)\n- Battery Storage (construction site and building-integrated)\n- Green Hydrogen\n- Mass Timber / CLT\n- AI Energy Management Systems",
        "operationId": "get_technologies",
        "responses": {
          "200": {
            "description": "Technology catalog",
            "content": {
              "application/json": {
                "schema": { "$ref": "#/components/schemas/TechnologiesResponse" }
              }
            }
          }
        }
      }
    },

    "/api/technology/{id}/comparison": {
      "get": {
        "tags": ["Technology"],
        "summary": "TCO comparison vs. conventional",
        "description": "Returns a full total cost of ownership (TCO) analysis comparing the specified renewable/green technology against its conventional equivalent, including multi-scenario analysis over 10–20 year horizons.\n\n**Technology IDs:**\n- `electric-excavator`\n- `solar-pv`\n- `green-building-systems`\n- `battery-storage`\n- `green-hydrogen`\n- `mass-timber`\n- `ai-energy-management`",
        "operationId": "get_technology_comparison",
        "parameters": [
          {
            "name": "id",
            "in": "path",
            "required": true,
            "description": "URL-safe technology identifier",
            "schema": {
              "type": "string",
              "enum": [
                "electric-excavator",
                "solar-pv",
                "green-building-systems",
                "battery-storage",
                "green-hydrogen",
                "mass-timber",
                "ai-energy-management"
              ],
              "example": "solar-pv"
            }
          }
        ],
        "responses": {
          "200": {
            "description": "TCO comparison data",
            "content": {
              "application/json": {
                "schema": { "$ref": "#/components/schemas/TechnologyComparisonResponse" }
              }
            }
          },
          "404": {
            "description": "Technology not found",
            "content": {
              "application/json": {
                "schema": { "$ref": "#/components/schemas/ErrorDetail" },
                "example": {
                  "detail": "Technology with id 'unknown-tech' not found.",
                  "code": "TECHNOLOGY_NOT_FOUND"
                }
              }
            }
          }
        }
      }
    },

    "/api/payback-analysis": {
      "get": {
        "tags": ["Financial"],
        "summary": "Payback periods by technology",
        "description": "Returns payback period analysis for all tracked technologies, with and without regulatory incentives.\n\n**Key data points:**\n- Range: 5–12 years depending on technology and incentive availability\n- Solar PV: 7–12 years base; 5–8 years with IRA credits\n- Electric equipment: 6–10 years base; 4–7 years with IRA credits\n- LEED management software: 3–6 months",
        "operationId": "get_payback_analysis",
        "responses": {
          "200": {
            "description": "Payback analysis data",
            "content": {
              "application/json": {
                "schema": { "$ref": "#/components/schemas/PaybackAnalysisResponse" }
              }
            }
          }
        }
      }
    },

    "/api/roi-scenarios": {
      "get": {
        "tags": ["Financial"],
        "summary": "Conservative / moderate / aggressive ROI projections",
        "description": "Returns three multi-year ROI projection scenarios for a representative mid-size construction firm ($150M revenue) adopting a portfolio of green technologies over a 10-year horizon.\n\n**Scenarios:**\n- **Conservative**: Minimum viable adoption (LEED AP credentialing + management software); no major capex\n- **Moderate**: Full sustainability program with on-site solar demonstration and electric equipment pilot\n- **Aggressive**: Comprehensive transformation including mass timber capability, full fleet electrification, and SBTi commitment",
        "operationId": "get_roi_scenarios",
        "responses": {
          "200": {
            "description": "ROI scenarios",
            "content": {
              "application/json": {
                "schema": { "$ref": "#/components/schemas/ROIScenariosResponse" }
              }
            }
          }
        }
      }
    },

    "/api/incentives": {
      "get": {
        "tags": ["Financial"],
        "summary": "Regulatory incentives and their financial impact",
        "description": "Returns all tracked federal, state, and provincial incentive programs relevant to green building and renewable energy adoption in construction.\n\n**Key programs:**\n- IRA Section 48 Investment Tax Credit (30%+ for solar, storage)\n- IRA Section 45 Production Tax Credit\n- Section 179D Energy-Efficient Commercial Buildings Deduction (expanded by IRA)\n- Federal LEED Gold mandate (GSA – market access, not financial)\n- State programs: CA, NY, CO, MA, WA, IL\n- Canada: Greener Homes Initiative, Clean Investment Tax Credit\n\n**Note:** Political risk flagged where OBBBA may modify credits.",
        "operationId": "get_incentives",
        "responses": {
          "200": {
            "description": "Incentives data",
            "content": {
              "application/json": {
                "schema": { "$ref": "#/components/schemas/IncentivesResponse" }
              }
            }
          }
        }
      }
    },

    "/api/case-studies": {
      "get": {
        "tags": ["Competitive"],
        "summary": "Benchmarking case studies",
        "description": "Returns competitive benchmarking profiles for six leading construction firms that have implemented renewable energy and sustainability strategies, with ROI metrics and lessons applicable to mid-size firms.\n\n**Firms profiled:**\n- **Mortenson** (Minneapolis) – $5.5B; #1 ENR Battery Storage; 40 GW wind, 12+ GW solar\n- **Gilbane** (Providence) – $7.3B; #7 ENR Green 2024; regenerative construction; SBTi Net Zero 2040\n- **Suffolk** (Boston) – $5B+; $2.6B annual green revenue; 43M+ SF decarbonization\n- **Swinerton** (San Francisco) – $4.5B; Timberlab mass timber; 200 MW solar\n- **Hensel Phelps** (Greeley) – $7.4B; $192M net-zero microgrid; $1M+ LEED savings\n- **Brasfield & Gorrie** (Birmingham) – $6.5B; #1 ENR Texas & Southeast; LEED upselling",
        "operationId": "get_case_studies",
        "responses": {
          "200": {
            "description": "Case studies data",
            "content": {
              "application/json": {
                "schema": { "$ref": "#/components/schemas/CaseStudiesResponse" }
              }
            }
          }
        }
      }
    },

    "/api/green-contracts": {
      "get": {
        "tags": ["Competitive"],
        "summary": "Contract win rate correlation data",
        "description": "Returns data on the correlation between green credentials/certifications and contract win rates, including certification market data, bid win rate evidence, contract premiums, and client preference analysis.\n\n**Key data points:**\n- LEED referenced in 71% of specs for projects >$50M\n- 35+ US states mandate LEED or equivalent for public buildings\n- GSA requires LEED Gold for new federal buildings\n- Sustainability criteria worth 10–25% of evaluation points in government RFPs\n- LEED O+M certifications grew 79% (2019–2024)\n- Green-certified firms effectively excluded from majority of large-project bids without credentials\n- 25–35% higher contract win rates on green-specified projects",
        "operationId": "get_green_contracts",
        "responses": {
          "200": {
            "description": "Green contract correlation data",
            "content": {
              "application/json": {
                "schema": { "$ref": "#/components/schemas/GreenContractsResponse" }
              }
            }
          }
        }
      }
    }
  },

  "components": {
    "schemas": {
      "HealthResponse": {
        "type": "object",
        "required": ["status", "version", "timestamp", "database"],
        "properties": {
          "status": {
            "type": "string",
            "description": "Service status",
            "example": "ok"
          },
          "version": {
            "type": "string",
            "description": "API version string",
            "example": "1.0.0"
          },
          "timestamp": {
            "type": "string",
            "description": "Current server UTC timestamp (ISO 8601)",
            "example": "2026-03-28T14:00:00Z"
          },
          "database": {
            "type": "string",
            "description": "Database connection status",
            "enum": ["ok", "degraded", "down"],
            "example": "ok"
          },
          "uptime_seconds": {
            "type": "number",
            "nullable": true,
            "description": "Process uptime in seconds",
            "example": 3600.5
          }
        }
      },

      "ErrorDetail": {
        "type": "object",
        "required": ["detail"],
        "properties": {
          "detail": {
            "type": "string",
            "description": "Human-readable error message"
          },
          "code": {
            "type": "string",
            "nullable": true,
            "description": "Machine-readable error code"
          },
          "field": {
            "type": "string",
            "nullable": true,
            "description": "Field name if this is a validation error"
          }
        }
      },

      "ConfidenceLevel": {
        "type": "string",
        "enum": ["HIGH", "MEDIUM", "LOW"],
        "description": "Research data confidence level based on source quality and corroboration"
      },

      "Region": {
        "type": "string",
        "enum": ["US", "Canada", "Mexico", "North America"]
      },

      "TechnologyCategory": {
        "type": "string",
        "enum": [
          "Electric Equipment",
          "Solar PV",
          "Green Building Systems",
          "Battery Storage",
          "Green Hydrogen",
          "Mass Timber",
          "Energy Management"
        ]
      },

      "ProjectionScenario": {
        "type": "string",
        "enum": ["conservative", "moderate", "aggressive"]
      },

      "FirmSize": {
        "type": "string",
        "enum": [
          "Small (<$50M)",
          "Mid-Size ($50M-$500M)",
          "Large (>$500M)"
        ]
      },

      "CertificationStandard": {
        "type": "string",
        "enum": [
          "LEED",
          "WELL",
          "Living Building Challenge",
          "Green Globes",
          "ENERGY STAR",
          "Passive House",
          "ISO 14001",
          "BREEAM",
          "Envision"
        ]
      },

      "SourceCitation": {
        "type": "object",
        "required": ["name", "organization", "confidence"],
        "properties": {
          "name": { "type": "string", "example": "Precedence Research — Green Building Materials Market" },
          "organization": { "type": "string", "example": "Precedence Research" },
          "url": { "type": "string", "nullable": true, "format": "uri" },
          "published_date": { "type": "string", "nullable": true, "example": "2026-02" },
          "confidence": { "$ref": "#/components/schemas/ConfidenceLevel" }
        }
      },

      "TimeSeriesPoint": {
        "type": "object",
        "required": ["year", "value", "unit"],
        "properties": {
          "year": { "type": "integer", "minimum": 2000, "maximum": 2040 },
          "value": { "type": "number" },
          "unit": { "type": "string", "example": "USD billions" },
          "estimated": { "type": "boolean", "default": false },
          "confidence": { "$ref": "#/components/schemas/ConfidenceLevel" }
        }
      },

      "KeyMetric": {
        "type": "object",
        "required": ["label", "value", "unit"],
        "properties": {
          "label": { "type": "string" },
          "value": { "type": "number" },
          "unit": { "type": "string" },
          "description": { "type": "string", "nullable": true }
        }
      },

      "AdoptionRateByFirmSize": {
        "type": "object",
        "required": [
          "firm_size",
          "formal_esg_program_pct_min",
          "formal_esg_program_pct_max",
          "leed_experience_pct_min",
          "leed_experience_pct_max",
          "electric_equipment_fleet_pct_min",
          "electric_equipment_fleet_pct_max",
          "has_dedicated_sustainability_team",
          "on_site_solar_deployed",
          "confidence"
        ],
        "properties": {
          "firm_size": { "$ref": "#/components/schemas/FirmSize" },
          "formal_esg_program_pct_min": { "type": "number", "minimum": 0, "maximum": 100, "example": 40 },
          "formal_esg_program_pct_max": { "type": "number", "minimum": 0, "maximum": 100, "example": 55 },
          "leed_experience_pct_min": { "type": "number", "minimum": 0, "maximum": 100, "example": 35 },
          "leed_experience_pct_max": { "type": "number", "minimum": 0, "maximum": 100, "example": 50 },
          "electric_equipment_fleet_pct_min": { "type": "number", "minimum": 0, "maximum": 100, "example": 1 },
          "electric_equipment_fleet_pct_max": { "type": "number", "minimum": 0, "maximum": 100, "example": 3 },
          "has_dedicated_sustainability_team": { "type": "string", "example": "Emerging" },
          "on_site_solar_deployed": { "type": "string", "example": "Occasional" },
          "confidence": { "$ref": "#/components/schemas/ConfidenceLevel" }
        }
      },

      "MarketSizeSnapshot": {
        "type": "object",
        "required": ["market_name", "value_usd_billions", "year", "source", "confidence"],
        "properties": {
          "market_name": { "type": "string" },
          "value_usd_billions": { "type": "number" },
          "year": { "type": "integer" },
          "is_projection": { "type": "boolean", "default": false },
          "cagr_pct": { "type": "number", "nullable": true },
          "cagr_period": { "type": "string", "nullable": true },
          "source": { "type": "string" },
          "confidence": { "$ref": "#/components/schemas/ConfidenceLevel" }
        }
      },

      "MarketDriverOrBarrier": {
        "type": "object",
        "required": ["name", "description", "severity", "trend", "confidence"],
        "properties": {
          "name": { "type": "string" },
          "description": { "type": "string" },
          "severity": { "type": "string", "enum": ["High", "Medium", "Low"] },
          "trend": { "type": "string", "enum": ["Increasing", "Stable", "Declining", "Mixed"] },
          "impact_on_mid_size_firms": { "type": "string", "nullable": true },
          "confidence": { "$ref": "#/components/schemas/ConfidenceLevel" }
        }
      },

      "MarketTrendsResponse": {
        "type": "object",
        "required": [
          "as_of_date",
          "global_green_building_market_2025_usd_b",
          "global_green_building_market_2034_projected_usd_b",
          "global_green_building_cagr_pct",
          "north_america_market_share_pct",
          "north_america_market_2025_usd_b",
          "electric_equipment_market_2025_usd_b_min",
          "electric_equipment_market_2025_usd_b_max",
          "electric_equipment_market_2030_projected_usd_b",
          "electric_equipment_cagr_pct",
          "ira_clean_energy_incentives_usd_b",
          "commercial_solar_adoption_boost_post_ira_pct",
          "buildings_global_co2_share_pct",
          "key_metrics",
          "adoption_by_firm_size",
          "global_market_time_series",
          "electric_equipment_time_series",
          "drivers",
          "barriers",
          "sources"
        ],
        "properties": {
          "as_of_date": { "type": "string", "example": "2026-03-28" },
          "global_green_building_market_2025_usd_b": { "type": "number", "example": 618.58 },
          "global_green_building_market_2034_projected_usd_b": { "type": "number", "example": 1374.23 },
          "global_green_building_cagr_pct": { "type": "number", "example": 9.29 },
          "north_america_market_share_pct": { "type": "number", "example": 35.0 },
          "north_america_market_2025_usd_b": { "type": "number", "example": 153.87 },
          "electric_equipment_market_2025_usd_b_min": { "type": "number", "example": 13.63 },
          "electric_equipment_market_2025_usd_b_max": { "type": "number", "example": 15.77 },
          "electric_equipment_market_2030_projected_usd_b": { "type": "number", "example": 34.72 },
          "electric_equipment_cagr_pct": { "type": "number", "example": 20.5 },
          "ira_clean_energy_incentives_usd_b": { "type": "number", "example": 270.0 },
          "commercial_solar_adoption_boost_post_ira_pct": { "type": "number", "example": 12.0 },
          "buildings_global_co2_share_pct": { "type": "number", "example": 37.0 },
          "key_metrics": {
            "type": "array",
            "items": { "$ref": "#/components/schemas/KeyMetric" }
          },
          "adoption_by_firm_size": {
            "type": "array",
            "items": { "$ref": "#/components/schemas/AdoptionRateByFirmSize" }
          },
          "global_market_time_series": {
            "type": "array",
            "items": { "$ref": "#/components/schemas/TimeSeriesPoint" }
          },
          "electric_equipment_time_series": {
            "type": "array",
            "items": { "$ref": "#/components/schemas/TimeSeriesPoint" }
          },
          "drivers": {
            "type": "array",
            "items": { "$ref": "#/components/schemas/MarketDriverOrBarrier" }
          },
          "barriers": {
            "type": "array",
            "items": { "$ref": "#/components/schemas/MarketDriverOrBarrier" }
          },
          "sources": {
            "type": "array",
            "items": { "$ref": "#/components/schemas/SourceCitation" }
          }
        }
      },

      "StateRegionalData": {
        "type": "object",
        "required": ["state"],
        "properties": {
          "state": { "type": "string", "example": "Massachusetts" },
          "leed_rank_2025": { "type": "integer", "nullable": true, "minimum": 1, "example": 1 },
          "leed_rank_2024": { "type": "integer", "nullable": true, "minimum": 1, "example": 1 },
          "rank_change_yoy": { "type": "integer", "nullable": true, "example": 0 },
          "key_drivers": { "type": "array", "items": { "type": "string" } },
          "key_policies": { "type": "array", "items": { "type": "string" } },
          "leed_credential_holders": { "type": "integer", "nullable": true, "example": 6920 },
          "notable_projects": { "type": "array", "items": { "type": "string" } }
        }
      },

      "CountryRegionalData": {
        "type": "object",
        "required": ["country", "leed_certified_space_sq_meters_m", "confidence"],
        "properties": {
          "country": { "$ref": "#/components/schemas/Region" },
          "leed_certified_space_sq_meters_m": { "type": "number", "example": 56.0 },
          "leed_certified_projects": { "type": "integer", "nullable": true },
          "global_leed_rank": { "type": "integer", "nullable": true },
          "market_size_2025_usd_b": { "type": "number", "nullable": true },
          "market_cagr_pct": { "type": "number", "nullable": true },
          "key_strategies": { "type": "array", "items": { "type": "string" } },
          "leading_provinces_or_states": { "type": "array", "items": { "type": "string" } },
          "key_drivers": { "type": "array", "items": { "type": "string" } },
          "key_challenges": { "type": "array", "items": { "type": "string" } },
          "notable_milestones": { "type": "array", "items": { "type": "string" } },
          "confidence": { "$ref": "#/components/schemas/ConfidenceLevel" }
        }
      },

      "RegionalDataResponse": {
        "type": "object",
        "required": ["as_of_date", "top_us_states_2025", "country_data", "sources"],
        "properties": {
          "as_of_date": { "type": "string", "example": "2026-03-28" },
          "top_us_states_2025": {
            "type": "array",
            "items": { "$ref": "#/components/schemas/StateRegionalData" }
          },
          "country_data": {
            "type": "array",
            "items": { "$ref": "#/components/schemas/CountryRegionalData" }
          },
          "sources": {
            "type": "array",
            "items": { "$ref": "#/components/schemas/SourceCitation" }
          }
        }
      },

      "FeasibilityScore": {
        "type": "object",
        "required": [
          "overall_score",
          "technical_maturity",
          "financial_viability",
          "regulatory_support",
          "workforce_readiness",
          "supply_chain_maturity",
          "mid_size_adoption_ease"
        ],
        "properties": {
          "overall_score": { "type": "number", "minimum": 0, "maximum": 10, "example": 7.5 },
          "technical_maturity": { "type": "number", "minimum": 0, "maximum": 10 },
          "financial_viability": { "type": "number", "minimum": 0, "maximum": 10 },
          "regulatory_support": { "type": "number", "minimum": 0, "maximum": 10 },
          "workforce_readiness": { "type": "number", "minimum": 0, "maximum": 10 },
          "supply_chain_maturity": { "type": "number", "minimum": 0, "maximum": 10 },
          "mid_size_adoption_ease": { "type": "number", "minimum": 0, "maximum": 10 }
        }
      },

      "TechnologyROIMetric": {
        "type": "object",
        "properties": {
          "payback_years_min": { "type": "number", "nullable": true },
          "payback_years_max": { "type": "number", "nullable": true },
